const incoming = $input.first().json || {};
const body = incoming.body ?? incoming;

function cleanString(v, fallback = '') {
  return String(v ?? fallback).trim();
}

const meetingUrl = cleanString(body.meeting_url || body.meetingUrl);
const region = cleanString(body.region, 'ap-northeast-1');
const botName = cleanString(body.bot_name || body.botName, 'RoyalSoft SDLC Recorder');
const projectName = cleanString(body.project_name || body.projectName, 'RoyalSoft TMS');
const meetingTitle = cleanString(body.meeting_title || body.title, `${projectName} SDLC Meeting`);
const languageCode = cleanString(body.language_code || body.languageCode, 'auto');
const transcriptionMode = cleanString(body.transcription_mode || body.transcriptionMode, 'prioritize_accuracy');
const realtimeTranscriptWebhook = cleanString(body.realtime_transcript_webhook || body.realtimeTranscriptWebhook, 'https://royalsoft.app.n8n.cloud/webhook/recall-realtime-transcript');
const enableRealtime = body.enable_realtime_transcript !== false;
const enableCanonical = body.enable_canonical_segments !== false;

// VALIDATION - Simple and reliable
if (!meetingUrl || meetingUrl.length < 10) {
  return [{ json: { success: false, status: 'error', error_code: 'MEETING_URL_REQUIRED', message: 'meeting_url is required.', fix_hint: 'Provide a valid meeting URL starting with https://.', retryable: true } }];
}

// Simple URL format check - just needs https:// and domain
if (!meetingUrl.startsWith('https://') && !meetingUrl.startsWith('http://')) {
  return [{ json: { success: false, status: 'error', error_code: 'INVALID_MEETING_URL', message: 'Meeting URL must start with https://', meeting_url: meetingUrl, fix_hint: 'Make sure the URL starts with https://.', retryable: true } }];
}

// Check for known meeting platforms
const hasValidDomain = meetingUrl.includes('meet.google.com') || 
                       meetingUrl.includes('zoom.us') || 
                       meetingUrl.includes('teams.microsoft.com') ||
                       meetingUrl.includes('webex.com');

if (!hasValidDomain) {
  return [{ json: { success: false, status: 'error', error_code: 'UNSUPPORTED_PLATFORM', message: 'URL must be from Google Meet, Zoom, Teams, or Webex. Recall.ai may not support other platforms.', meeting_url: meetingUrl, fix_hint: 'Use a Google Meet, Zoom, Teams, or Webex URL.', retryable: false } }];
}

// Region validation
if (!['ap-northeast-1','ap-southeast-1','us-west-2','us-east-1','eu-central-1'].includes(region)) {
  return [{ json: { success: false, status: 'error', error_code: 'INVALID_REGION', message: `Unsupported Recall region: ${region}. Use: ap-northeast-1, us-west-2, us-east-1, eu-central-1`, fix_hint: 'Use one of the supported regions.', retryable: true } }];
}

// ALL VALID - Return normalized data
return [{
  json: {
    valid: true,
    meeting_url: meetingUrl,
    region,
    bot_name: botName,
    project_name: projectName,
    meeting_title: meetingTitle,
    language_code: languageCode,
    transcription_mode: transcriptionMode,
    realtime_transcript_webhook: realtimeTranscriptWebhook,
    enable_realtime_transcript: enableRealtime,
    enable_canonical_segments: enableCanonical
  }
}];

