const envelope = $input.first().json || {};
const start = $('Code - Normalize Start').first().json || {};

function tryJson(v) {
  if (typeof v !== 'string') return v;
  try { return JSON.parse(v); } catch (e) { return v; }
}

function unwrap(v) {
  v = tryJson(v);
  if (Array.isArray(v) && v.length === 1) return unwrap(v[0]);
  if (!v || typeof v !== 'object') return v;
  // n8n/HTTP nodes may wrap responses in body/data/response/result.
  for (const key of ['body','data','response','result','json']) {
    if (v[key] && typeof v[key] === 'object') {
      const inner = unwrap(v[key]);
      if (inner && typeof inner === 'object' && (inner.id || inner.bot_id || inner.status_changes || inner.error || inner.detail || inner.message)) return inner;
    }
  }
  return v;
}

function findId(v, depth = 0) {
  if (!v || depth > 4) return null;
  if (typeof v !== 'object') return null;
  if (v.id) return v.id;
  if (v.bot_id) return v.bot_id;
  if (v.uuid) return v.uuid;
  for (const key of ['body','data','response','result','raw','json']) {
    const id = findId(v[key], depth + 1);
    if (id) return id;
  }
  return null;
}

function latestStatus(v) {
  const changes = Array.isArray(v?.status_changes) ? v.status_changes : [];
  return changes.length ? (changes[changes.length - 1].code || changes[changes.length - 1].status || 'created') : (v?.status || 'created');
}

function extractError(v) {
  if (!v || typeof v !== 'object') return String(v || 'Unknown error');
  if (v.error?.message) return v.error.message;
  if (typeof v.error === 'string') return v.error;
  if (v.detail) return typeof v.detail === 'string' ? v.detail : JSON.stringify(v.detail);
  if (v.message && !v.id) return v.message;
  if (v.errors) return JSON.stringify(v.errors);
  return 'Recall create bot response did not include id.';
}

const raw = unwrap(envelope);
const botId = findId(raw);

if (!botId) {
  return [{ json: {
    status: 'error',
    success: false,
    error_code: 'RECALL_CREATE_NO_BOT_ID',
    message: extractError(raw),
    bot_id: null,
    endpoint: `https://${start.region}.recall.ai/api/v1/bot/`,
    meeting_url: start.meeting_url,
    region: start.region,
    raw_response: envelope,
    normalized_response: raw,
    fix_hint: 'Open this n8n execution and inspect HTTP - Create Recall Bot. Common causes: wrong region for API key, invalid/expired key, inactive workflow, invalid Google Meet URL, or Recall 507 capacity error.'
  }}];
}

return [{ json: {
  status: 'created',
  success: true,
  message: 'Bot created successfully.',
  bot_id: botId,
  id: botId,
  bot_status: latestStatus(raw),
  meeting_url: raw.meeting_url || start.meeting_url,
  region: start.region,
  project_name: start.project_name,
  raw: raw,
  raw_response: envelope
}}];

const incoming = $input.first().json || {};
const body = incoming.body ?? incoming;
const botId = String(body.bot_id || body.botId || body.id || '').trim();
const region = String(body.region || 'ap-northeast-1').trim();
if (!botId) return [{ json: { success: false, status: 'error', error_code: 'BOT_ID_REQUIRED', message: 'bot_id is required.', fix_hint: 'Provide a valid bot_id from the Join Meeting response.', retryable: true } }];
return [{ json: { valid: true, bot_id: botId, region } }];

const envelope = $input.first().json || {};
const req = $('Code - Normalize Status').first().json || {};
function unwrap(v){
  if(typeof v==='string'){try{return JSON.parse(v)}catch(e){return v}}
  if(Array.isArray(v)&&v.length===1)return unwrap(v[0]);
  if(v&&typeof v==='object'){
    for(const k of ['body','data','response','result','json']){
      if(v[k]&&typeof v[k]==='object'){
        const inner=unwrap(v[k]);
        if(inner&&typeof inner==='object'&&(inner.id||inner.status_changes||inner.error||inner.detail||inner.message))return inner;
      }
    }
  }
  return v;
}
function latest(v){const c=Array.isArray(v?.status_changes)?v.status_changes:[];return c.length?(c[c.length-1].code||c[c.length-1].status||'unknown'):(v?.status||'unknown')}
const raw=unwrap(envelope);
if(!raw || typeof raw!=='object' || raw.error || raw.detail || (raw.message && !raw.id)){
  return [{json:{status:'error',success:false,error_code:'RECALL_STATUS_FAILED',message:raw?.detail||raw?.error?.message||raw?.error||raw?.message||'Recall status failed.',fix_hint:'Check Recall API status and bot_id.',retryable:true,bot_id:req.bot_id,raw_response:envelope,normalized_response:raw}}];
}
return [{json:{status:'ok',success:true,bot_id:raw.id||req.bot_id,bot_status:latest(raw),raw,raw_response:envelope}}];

const incoming = $input.first().json || {};
const body = incoming.body ?? incoming;
const botId = String(body.bot_id || body.botId || body.id || '').trim();
const region = String(body.region || 'ap-northeast-1').trim();
if (!botId) return [{ json: { success: false, status: 'error', error_code: 'BOT_ID_REQUIRED', message: 'bot_id is required.', fix_hint: 'Provide a valid bot_id from the Join Meeting response.', retryable: true } }];
return [{ json: { valid: true, bot_id: botId, region } }];

const envelope = $input.first().json || {};
const req = $('Code - Normalize Transcript').first().json || {};

// ── PRIORITY: propagate not_ready / no_results / no_done_transcript ────────
// When Code - Extract Transcript URL returns these statuses, HTTP - Download
// S3 fails (undefined URL) and sends an error envelope here. We must recover
// the original status from that node so the HTML auto-retry loop works.
try {
  const extractResult = $('Code - Extract Transcript URL').first().json;
  if (extractResult && ['not_ready', 'no_results', 'no_done_transcript'].includes(extractResult.status)) {
    return [{ json: { ...extractResult, bot_id: extractResult.bot_id || req.bot_id } }];
  }
  // Also propagate hard errors from the list endpoint
  if (extractResult && extractResult.status === 'error' && extractResult.error_code &&
      extractResult.error_code.startsWith('RECALL_LIST_HTTP_')) {
    return [{ json: { ...extractResult, bot_id: extractResult.bot_id || req.bot_id } }];
  }
} catch(_priorityErr) {}

console.log("ALL ITEMS COUNT:", $input.all().length);
console.log("RAW INPUT KEYS:", Object.keys(envelope));
console.log("ENVELOPE TYPE:", typeof envelope);
console.log("BODY TYPE:", typeof envelope.body, envelope.body ? envelope.body.constructor?.name || typeof envelope.body : 'N/A');
console.log("BODY IS STRING:", typeof envelope.body === 'string');
console.log("BODY IS ARRAY:", Array.isArray(envelope.body));
console.log("BODY LENGTH:", typeof envelope.body === 'string' ? envelope.body.length : (Array.isArray(envelope.body) ? envelope.body.length : 'N/A'));
if (typeof envelope.body === 'string') console.log("BODY PREVIEW (first 200):", envelope.body.slice(0, 200));
if (typeof envelope.data === 'string') console.log("DATA PREVIEW (first 200):", envelope.data.slice(0, 200));
console.log("ENVELOPE STATUS:", envelope.status);

// ===== CASE A: Segments already in envelope (from Code - Extract URL via https) =====
if (envelope.status === 'done' && envelope.segments && Array.isArray(envelope.segments) && envelope.segments.length > 0) {
  console.log("Segments from envelope.segments:", envelope.segments.length);
  return processSegments(envelope.segments, envelope);
}

// ===== CASE B: s3_download_failed - but download_url available, let HTTP node handle it =====
if (envelope.status === 's3_download_failed' || envelope.status === 's3_parse_failed') {
  // If download_url exists, let it pass through to HTTP node (which has continueOnFail: true)
  if (envelope.download_url) {
    return [{ json: envelope }];
  }
  return [{ json: {
    success: false,
    status: envelope.status,
    message: envelope.message || 'S3 download failed.',
    error_detail: envelope.error_detail || '',
    bot_id: envelope.bot_id || req.bot_id || '',
    transcript_id: envelope.transcript_id || '',
    retryable: true,
    fix_hint: 'Try again. If persists, the S3 pre-signed URL may have expired.'
  }}];
}

// ===== CASE C: Input from HTTP - Download Transcript S3 node =====
// HTTP error detection for S3 node failures
const httpErrStatusCode = envelope.statusCode || envelope.status_code || envelope.response?.statusCode || envelope.response?.status || (typeof envelope.status === 'number' ? envelope.status : 0) || 0;
if (httpErrStatusCode >= 400 || envelope.error || envelope.error_code || (envelope.body && (envelope.body.error || envelope.body.error_code))) {
  const errBody = envelope.body || envelope.data || envelope.error || {};
  const detail = errBody.detail || errBody.message || errBody.error || (typeof errBody === 'string' ? errBody : JSON.stringify(errBody).slice(0, 200));
  const statusCode = httpErrStatusCode || '?';
  return [{ json: {
    success: false,
    status: 'http_error',
    status_code: statusCode,
    error_code: 'RECALL_HTTP_' + statusCode,
    message: 'S3 download returned HTTP ' + statusCode + ': ' + detail,
    raw_response: envelope,
    fix_hint: 'S3 download URL may have expired. Try fetching transcript list again.',
    retryable: [401, 404, 425, 429, 500, 502, 503].includes(Number(statusCode))
  }}];
}

// Extract segments from S3 HTTP response
let segments = [];

// Case 1: n8n multi-item response (HTTP node splits JSON arrays)
const allItems = $input.all();
if (allItems.length > 1) {
  segments = allItems.map(item => item.json).filter(x => x && typeof x === 'object');
  console.log("Segments from multi-item S3 response:", segments.length);
}
// Case 2: Direct array
else if (Array.isArray(envelope) && envelope.length > 0) {
  segments = envelope;
  console.log("Segments from direct array:", segments.length);
}
// Case 3: body array
else if (envelope?.body && Array.isArray(envelope.body) && envelope.body.length > 0) {
  segments = envelope.body;
  console.log("Segments from envelope.body:", segments.length);
}
// Case 4: body string (JSON.parse needed)
else if (envelope?.body && typeof envelope.body === 'string' && envelope.body.length > 0) {
  try {
    const parsed = JSON.parse(envelope.body);
    if (Array.isArray(parsed) && parsed.length > 0) {
      segments = parsed;
      console.log("Segments from parsed envelope.body string:", segments.length);
    }
  } catch (e) {
    console.log("Failed to parse envelope.body as JSON:", e.message.slice(0, 100));
    // Try partial parse - maybe it's truncated
    try {
      const trimmed = envelope.body.trim();
      if (trimmed.startsWith('[') && trimmed.endsWith(']')) {
        // Already tried full parse, failed. Try without last char in case truncated
        const partial = JSON.parse(trimmed.slice(0, -1) + ']');
        if (Array.isArray(partial) && partial.length > 0) {
          segments = partial;
          console.log("Segments from partial parse:", segments.length);
        }
      }
    } catch (e2) {}
  }
}
// Case 5: body is object/Buffer (n8n treats application/octet-stream as binary)
else if (envelope?.body && typeof envelope.body === 'object' && envelope.body !== null) {
  // Buffer object - try toString()
  try {
    const str = String(envelope.body);
    if (str.length > 0) {
      const parsed = JSON.parse(str);
      if (Array.isArray(parsed) && parsed.length > 0) {
        segments = parsed;
        console.log("Segments from Buffer.toString():", segments.length);
      }
    }
  } catch (e) {
    console.log("Failed to parse Buffer body:", e.message.slice(0, 100));
  }
}
// Case 6: raw envelope is string (HTTP returned raw JSON string)
else if (typeof envelope === 'string' && envelope.length > 0) {
  try {
    const parsed = JSON.parse(envelope);
    if (Array.isArray(parsed) && parsed.length > 0) {
      segments = parsed;
      console.log("Segments from parsed envelope string:", segments.length);
    }
  } catch (e) {
    console.log("Failed to parse envelope as JSON:", e.message.slice(0, 100));
  }
}
// Case 7: data array
else if (envelope?.data && Array.isArray(envelope.data) && envelope.data.length > 0) {
  segments = envelope.data;
  console.log("Segments from envelope.data:", segments.length);
}
// Case 8: data is string (JSON.parse needed)
else if (envelope?.data && typeof envelope.data === 'string' && envelope.data.length > 0) {
  try {
    const parsed = JSON.parse(envelope.data);
    if (Array.isArray(parsed) && parsed.length > 0) {
      segments = parsed;
      console.log("Segments from parsed envelope.data:", segments.length);
    }
  } catch (e) {
    console.log("Failed to parse envelope.data as JSON:", e.message.slice(0, 100));
  }
}

// Case 9: RECURSIVE SEARCH - search ALL object properties for arrays
if (segments.length === 0) {
  function deepFindArray(obj, depth) {
    if (depth > 6 || !obj || typeof obj !== 'object') return null;
    if (Array.isArray(obj) && obj.length > 0) {
      // Check if this looks like a segments array
      const first = obj[0];
      if (first && typeof first === 'object' && (first.participant || first.words || first.speaker || first.text || first.speaker_name)) {
        return obj;
      }
    }
    const keys = Object.keys(obj);
    for (const key of keys) {
      try {
        const result = deepFindArray(obj[key], depth + 1);
        if (result) return result;
      } catch(e) {}
    }
    return null;
  }
  try {
    const found = deepFindArray(envelope, 0);
    if (found) {
      segments = found;
      console.log("Segments from deep recursive search:", segments.length);
    }
  } catch(e) {
    console.log("Deep search failed:", e.message.slice(0, 100));
  }
}

if (segments.length === 0) {
  const rawJson = envelope;
  const hasAnyData = JSON.stringify(rawJson).length > 50;
  if (hasAnyData) {
    const results = rawJson.results || rawJson.body?.results || rawJson.data?.results;
    if (Array.isArray(results)) {
      return [{ json: {
        success: true,
        status: 'no_segments',
        segment_count: 0,
        transcript_count: results.length,
        message: 'Transcript list returned but S3 download failed or returned empty.',
        retry_after_seconds: 30
      }}];
    }
    return [{ json: {
      success: false,
      status: 'parse_failed',
      error_code: 'NO_SEGMENTS_FOUND',
      message: 'S3 download returned no segments. Unknown response format.',
      raw_preview: JSON.stringify(rawJson).slice(0, 500),
      raw_body_type: typeof rawJson.body,
      raw_body_constructor: rawJson.body ? rawJson.body.constructor?.name || typeof rawJson.body : 'N/A',
      raw_body_is_string: typeof rawJson.body === 'string',
      raw_body_is_array: Array.isArray(rawJson.body),
      raw_body_length: typeof rawJson.body === 'string' ? rawJson.body.length : (Array.isArray(rawJson.body) ? rawJson.body.length : (rawJson.body ? 'object' : 'none')),
      raw_body_preview: typeof rawJson.body === 'string' ? rawJson.body.slice(0, 300) : (Array.isArray(rawJson.body) ? 'Array(' + rawJson.body.length + ')' : JSON.stringify(rawJson.body).slice(0, 300)),
      fix_hint: 'Check S3 download response format in n8n execution log.'
    }}];
  }
  return [{ json: {
    success: true,
    status: 'not_ready',
    segment_count: 0,
    retry_after_seconds: 30,
    message: 'Transcript not ready or empty. Try again after 30 seconds.'
  }}];
}

// ===== PROCESS SEGMENTS =====
return processSegments(segments, envelope);

// ===== SHARED PROCESSING FUNCTION =====
function processSegments(segments, sourceEnvelope) {
  function getText(seg) {
    if (!seg) return '';
    if (typeof seg === 'string') return seg;
    if (Array.isArray(seg.words)) {
      return seg.words.map(w => w.text || w.word || '').filter(t => t).join(' ');
    }
    if (seg.text) return seg.text;
    if (seg.transcript) return seg.transcript;
    if (seg.content) return seg.content;
    if (seg.data?.text) return seg.data.text;
    if (seg.data?.content) return seg.data.content;
    if (Array.isArray(seg.data?.words)) return seg.data.words.map(w => w.text || w.word || '').join(' ');
    return '';
  }

  function getSpeaker(seg) {
    if (!seg) return 'Speaker';
    if (seg.participant) {
      return seg.participant.name || seg.participant.speaker || seg.participant.id || 'Speaker';
    }
    return seg.speaker || seg.speaker_name || seg.participant_name || seg.participant?.name ||
           seg.from_user || seg.name || seg.full_name || seg.data?.participant?.name ||
           seg.data?.speaker || 'Speaker';
  }

  function getStartMs(seg) {
    if (!seg) return 0;
    if (Array.isArray(seg.words) && seg.words.length > 0 && seg.words[0].start_timestamp) {
      const rel = seg.words[0].start_timestamp.relative;
      if (rel !== undefined) return Math.round(rel * 1000);
    }
    const n = Number(seg?.start_timestamp?.relative || seg?.start_timestamp || seg?.start_time || seg?.start || seg?.offset || seg?.data?.start_timestamp?.relative || 0);
    return n || 0;
  }

  function getEndMs(seg) {
    if (!seg) return 0;
    if (Array.isArray(seg.words) && seg.words.length > 0) {
      const last = seg.words[seg.words.length - 1];
      if (last?.end_timestamp?.relative !== undefined) return Math.round(last.end_timestamp.relative * 1000);
    }
    const n = Number(seg?.end_timestamp?.relative || seg?.end_timestamp || seg?.end_time || seg?.end || 0);
    return n || 0;
  }

  function stableHash(input) {
    let hash = 0;
    for (let i = 0; i < input.length; i++) {
      const char = input.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash;
    }
    return 'seg_' + Math.abs(hash).toString(16).padStart(8, '0');
  }

  const processed = segments.map((s, i) => {
    const rawText = getText(s).replace(/\s+/g, ' ').trim();
    const sp = getSpeaker(s);
    const startMs = getStartMs(s);
    const endMs = getEndMs(s);
    const startSec = Math.round(startMs > 10000 ? startMs/1000 : startMs);
    const endSec = Math.round(endMs > 10000 ? endMs/1000 : endMs);
    const minutes = Math.floor(startSec / 60);
    const secs = String(startSec % 60).padStart(2, '0');
    const segId = stableHash(String(req.bot_id || '') + sp + String(startMs) + rawText.slice(0, 50));
    return {
      segment_id: segId,
      meeting_id: req.bot_id || '',
      bot_id: req.bot_id || '',
      sequence_no: i + 1,
      speaker_id: sp.replace(/\s+/g, '_').toLowerCase(),
      speaker_name: sp,
      start_ms: startMs,
      end_ms: endMs,
      start_time: String(minutes).padStart(2, '0') + ':' + secs,
      start_seconds: startSec,
      end_seconds: endSec,
      time: minutes + ':' + secs,
      text_raw: rawText,
      text_clean: rawText,
      treated_text: '',
      language_detected: 'unknown',
      confidence: null,
      is_final: true,
      source: 'recall_final_transcript',
      raw_json: s
    };
  }).filter(s => s.text_raw);

  const seen = new Set();
  const uniqueSegments = processed.filter(s => {
    if (seen.has(s.segment_id)) return false;
    seen.add(s.segment_id);
    return true;
  });

  uniqueSegments.sort((a, b) => a.start_ms - b.start_ms);
  uniqueSegments.forEach((s, i) => s.sequence_no = i + 1);

  const speakerSet = new Set(uniqueSegments.map(s => s.speaker_name));
  const totalDuration = uniqueSegments.length > 0 ? Math.max(...uniqueSegments.map(s => s.end_seconds || s.start_seconds)) : 0;

  const cleaningStats = {
    original_count: segments.length,
    cleaned_count: uniqueSegments.length,
    empty_removed: segments.length - processed.filter(s => s.text_raw).length + (segments.length - uniqueSegments.length),
    duplicates_removed: segments.length - uniqueSegments.length,
    merged_segments: 0,
    speaker_count: speakerSet.size,
    total_duration_seconds: totalDuration
  };

  const transcript_text = uniqueSegments.map(s => '[' + s.start_time + '] ' + s.speaker_name + ': ' + s.text_clean).join('\n');

  if (!uniqueSegments.length) {
    return [{ json: {
      success: true,
      status: 'no_segments',
      segment_count: 0,
      message: 'S3 returned segments but all were empty or filtered out.',
      cleaning_stats: cleaningStats
    }}];
  }

  return [{
    json: {
      status: 'ok',
