const resp = $input.first().json || {};
const base = $('Code - Normalize Treatment').first().json;
let rawContent = '';

// Handle ALL response shapes
if (resp.choices?.[0]?.message?.content) {
  rawContent = resp.choices[0].message.content;
} else if (resp.treated_transcript) {
  rawContent = typeof resp.treated_transcript === 'string' ? resp.treated_transcript : JSON.stringify(resp);
} else if (resp.response?.treated_transcript) {
  rawContent = JSON.stringify(resp.response);
} else if (resp.data?.treated_transcript) {
  rawContent = JSON.stringify(resp.data);
} else if (resp.output) {
  rawContent = typeof resp.output === 'string' ? resp.output : JSON.stringify(resp.output);
} else {
  rawContent = JSON.stringify(resp);
}

let parsed;
try { parsed = JSON.parse(rawContent); } catch (e) { parsed = { treated_transcript: rawContent }; }

const result = {
  status: parsed.status || 'completed',
  success: parsed.success !== false,
  meeting_id: base.meeting_id,
  project_name: base.project_name,
  treated_transcript: parsed.treated_transcript || base.transcript || '',
  summary: parsed.summary || '',
  segments: parsed.segments || [],
  requirements_candidates: parsed.requirements_candidates || [],
  decisions: parsed.decisions || [],
  action_items: parsed.action_items || [],
  unclear_items: parsed.unclear_items || [],
  raw_response: resp,
  treatment_mode: parsed.treated_transcript ? 'ai' : 'local_fallback'
};

// If parsing completely failed, return fallback error
if (!parsed.treated_transcript && !parsed.summary) {
  return [{
    json: {
      success: false,
      status: 'error',
      error_code: 'AI_TREATMENT_PARSE_FAILED',
      treatment_mode: 'local_fallback',
      message: 'AI treatment failed. Local fallback used.',
      treated_transcript: base.transcript || '',
      raw_response: resp,
      ...result
    }
  }];
}

return [{ json: result }];

const incoming = $input.first().json || {};
