function stableHash(input) {
  let hash = 0;
  for (let i = 0; i < input.length; i++) {
    const char = input.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return 'seg_' + Math.abs(hash).toString(16).padStart(8, '0');
}

const bot_id = body.bot_id || body.botId || body.id || '';
const meeting_id = body.meeting_id || body.meetingId || bot_id;
const event_type = body.event_type || body.event || body.type || 'transcript.data';
const segment = body.data || body.segment || body;

const speaker_name = segment?.speaker || segment?.speaker_name || segment?.participant?.name || segment?.name || body.speaker || 'Speaker';
const speaker_id = segment?.speaker_id || segment?.participant?.id || speaker_name.replace(/\s+/g, '_').toLowerCase();
const text_raw = segment?.text || segment?.transcript || segment?.data?.text || segment?.content || '';
const start_ms = Number(segment?.start_timestamp?.relative || segment?.start_timestamp || segment?.start || segment?.offset || 0) || 0;
const end_ms = Number(segment?.end_timestamp?.relative || segment?.end_timestamp || segment?.end || 0) || 0;
const words = segment?.words || segment?.data?.words || [];

const segment_id = stableHash(String(bot_id) + speaker_name + String(start_ms) + text_raw.slice(0, 80));

return [{
  json: {
    success: true,
    source: 'recall_realtime_transcript',
    bot_id: String(bot_id),
    meeting_id: String(meeting_id),
    event_type: String(event_type),
