      raw_json: segment
    },
    raw_event: incoming
  }
}];

const envelope = $input.first().json || {};
const req = $('Code - Normalize Transcript').first().json || {};

// ── HTTP error detection from GET transcript list ──────────────────────────
const httpStatus = envelope.statusCode || envelope.status_code ||
  (typeof envelope.status === 'number' ? envelope.status : 0);
if (httpStatus >= 400 || (envelope.error && !envelope.results) ||
    (envelope.detail && !envelope.results)) {
  const detail = envelope.detail || envelope.error?.message || envelope.error || 'Recall API error';
  const sc = httpStatus || '?';
  return [{ json: {
    success: false,
    status: 'error',
    error_code: 'RECALL_LIST_HTTP_' + sc,
    message: 'Recall.ai transcript list returned HTTP ' + sc + ': ' + detail,
    fix_hint: sc === 401 ? 'API key or region mismatch. Check Recall.ai dashboard.' :
              sc === 404 ? 'Bot not found or wrong region.' :
              sc === 429 ? 'Rate limited. Wait 30s and retry.' :
              'Check n8n execution logs.',
    retryable: [429, 500, 502, 503].includes(Number(sc)),
    bot_id: req.bot_id,
    region: req.region,
    raw_response: envelope
  }}];
}

// ── Normalise transcript list response ────────────────────────────────────
const raw = envelope.results || envelope.body?.results || envelope.data?.results ||
            envelope.response?.results || envelope.result?.results || [];

console.log("TRANSCRIPT LIST RESULTS COUNT:", raw.length);

if (!Array.isArray(raw) || raw.length === 0) {
  return [{ json: {
    success: true,
    status: 'no_results',
    message: 'No transcript results found for this bot yet.',
    retry_after_seconds: 15,
    bot_id: req.bot_id,
    region: req.region,
    raw_transcript_list: []
  }}];
}

// ── Find best 'done' transcript with download_url ─────────────────────────
let targetTranscript = null;
for (const t of raw) {
  const statusCode = t?.status?.code || '';
  if (statusCode === 'done' && t?.data?.download_url) {
    if (!targetTranscript || new Date(t.created_at) > new Date(targetTranscript.created_at)) {
      targetTranscript = t;
    }
  }
}

if (!targetTranscript) {
  const hasProcessing = raw.some(t => {
    const sc = t?.status?.code || '';
    return ['processing', 'generating', 'pending', 'started', 'in_progress'].includes(sc);
  });
  if (hasProcessing) {
    return [{ json: {
      success: true,
      status: 'not_ready',
      message: 'Transcript is being generated. Try again shortly.',
      retry_after_seconds: 15,
      bot_id: req.bot_id,
      region: req.region,
      raw_results_count: raw.length,
      raw_transcript_list: raw
    }}];
  }
  // No done transcript but also no processing ones
  const hasMissing = raw.some(t => t?.status?.code === 'done' && !t?.data?.download_url);
  return [{ json: {
    success: true,
    status: hasMissing ? 'no_done_transcript' : 'no_results',
    message: hasMissing
      ? 'Transcript exists but no completed downloadable JSON found yet.'
      : 'No transcript results found for this bot yet.',
    retry_after_seconds: 15,
    bot_id: req.bot_id,
    region: req.region,
    raw_results_count: raw.length,
    raw_transcript_list: raw
  }}];
}

const downloadUrl = targetTranscript.data.download_url;
const transcriptId = targetTranscript.id;
console.log("TARGET TRANSCRIPT:", transcriptId);
console.log("DOWNLOAD URL (first 80):", (downloadUrl || '').slice(0, 80));

return [{ json: {
  success: true,
  status: 'done',
  download_url: downloadUrl,
  transcript_id: transcriptId,
  bot_id: req.bot_id,
  region: req.region,
  transcript_created_at: targetTranscript.created_at,
  raw_results_count: raw.length,
  raw_transcript_list: raw
}}];
